+func floatEqualsOneOf(v float64, allowed []float64) bool {
+	const eps = 1e-9
+	for _, a := range allowed {
+		d := v - a
+		if d < 0 {
+			d = -d
+		}
+		if d <= eps {
+			return true
+		}
+	}
+	return false
+}
